// Learn: Notice casts, overflow, and exact math.
byte wrapped = (byte) 200;
// MAX_VALUE + 1 wraps around for int arithmetic.
int overflow = Integer.MAX_VALUE + 1;
long widened = wrapped;
int exact = Math.addExact(10, 5);
System.out.println(wrapped);
System.out.println(overflow);
System.out.println(widened + exact);
